import os
import io
import csv
import numpy as np
import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import pandas as pd
from PIL import Image
import pickle
from datetime import datetime

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_PATH = 'community_model.h5'
TRAINING_DATA_PATH = 'training_data'
METADATA_PATH = 'metadata.pkl'

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(TRAINING_DATA_PATH, exist_ok=True)

class CommunityModel:
    def __init__(self, num_classes=10, img_height=224, img_width=224):
        self.num_classes = num_classes
        self.img_height = img_height
        self.img_width = img_width
        self.model = None
        self.metadata = {
            'total_samples': 0,
            'contributions': [],
            'accuracy_history': []
        }
        self.load_metadata()
        
    def build_model(self):
        self.model = keras.Sequential([
            layers.Rescaling(1./255, input_shape=(self.img_height, self.img_width, 3)),
            layers.Conv2D(32, 3, padding='same', activation='relu'),
            layers.MaxPooling2D(),
            layers.Conv2D(64, 3, padding='same', activation='relu'),
            layers.MaxPooling2D(),
            layers.Conv2D(128, 3, padding='same', activation='relu'),
            layers.MaxPooling2D(),
            layers.Flatten(),
            layers.Dense(128, activation='relu'),
            layers.Dropout(0.5),
            layers.Dense(self.num_classes, activation='softmax')
        ])
        
        self.model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
    
    def load_model(self):
        if os.path.exists(MODEL_PATH):
            self.model = keras.models.load_model(MODEL_PATH)
            return True
        return False
    
    def save_model(self):
        if self.model:
            self.model.save(MODEL_PATH)
    
    def load_metadata(self):
        if os.path.exists(METADATA_PATH):
            with open(METADATA_PATH, 'rb') as f:
                self.metadata = pickle.load(f)
    
    def save_metadata(self):
        with open(METADATA_PATH, 'wb') as f:
            pickle.dump(self.metadata, f)
    
    def train_from_csv(self, csv_path, image_column, label_column, batch_size=32, epochs=10):
        df = pd.read_csv(csv_path)
        
        images = []
        labels = []
        
        for idx, row in df.iterrows():
            img_path = row[image_column]
            if os.path.exists(img_path):
                img = Image.open(img_path).convert('RGB')
                img = img.resize((self.img_width, self.img_height))
                images.append(np.array(img))
                labels.append(int(row[label_column]))
        
        if not images:
            return None
        
        images = np.array(images)
        labels = np.array(labels)
        
        if self.model is None:
            self.build_model()
        
        history = self.model.fit(
            images, labels,
            batch_size=batch_size,
            epochs=epochs,
            validation_split=0.2,
            verbose=1
        )
        
        self.metadata['total_samples'] += len(images)
        self.metadata['accuracy_history'].append({
            'timestamp': datetime.now().isoformat(),
            'accuracy': float(history.history['accuracy'][-1]),
            'val_accuracy': float(history.history['val_accuracy'][-1])
        })
        
        self.save_model()
        self.save_metadata()
        
        return history
    
    def train_from_directory(self, data_dir, batch_size=32, epochs=10):
        train_ds = tf.keras.utils.image_dataset_from_directory(
            data_dir,
            validation_split=0.2,
            subset="training",
            seed=123,
            image_size=(self.img_height, self.img_width),
            batch_size=batch_size
        )
        
        val_ds = tf.keras.utils.image_dataset_from_directory(
            data_dir,
            validation_split=0.2,
            subset="validation",
            seed=123,
            image_size=(self.img_height, self.img_width),
            batch_size=batch_size
        )
        
        if self.model is None:
            self.build_model()
        
        history = self.model.fit(
            train_ds,
            validation_data=val_ds,
            epochs=epochs
        )
        
        self.save_model()
        self.save_metadata()
        
        return history
    
    def add_training_sample(self, image_file, label, contributor_id):
        label_dir = os.path.join(TRAINING_DATA_PATH, str(label))
        os.makedirs(label_dir, exist_ok=True)
        
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S_%f')
        filename = f"{timestamp}_{secure_filename(image_file.filename)}"
        filepath = os.path.join(label_dir, filename)
        
        img = Image.open(image_file).convert('RGB')
        img = img.resize((self.img_width, self.img_height))
        img.save(filepath)
        
        self.metadata['contributions'].append({
            'contributor_id': contributor_id,
            'timestamp': datetime.now().isoformat(),
            'label': label,
            'filepath': filepath
        })
        
        self.save_metadata()
        
        return filepath

community_model = CommunityModel()
if not community_model.load_model():
    community_model.build_model()

@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file uploaded'}), 400
    
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'Empty filename'}), 400
    
    image_column = request.form.get('image_column', 'image_path')
    label_column = request.form.get('label_column', 'label')
    epochs = int(request.form.get('epochs', 10))
    batch_size = int(request.form.get('batch_size', 32))
    
    filename = secure_filename(file.filename)
    filepath = os.path.join(UPLOAD_FOLDER, filename)
    file.save(filepath)
    
    try:
        history = community_model.train_from_csv(
            filepath, 
            image_column, 
            label_column,
            batch_size=batch_size,
            epochs=epochs
        )
        
        if history is None:
            return jsonify({'error': 'No valid images found in CSV'}), 400
        
        return jsonify({
            'message': 'Training completed successfully',
            'accuracy': float(history.history['accuracy'][-1]),
            'val_accuracy': float(history.history['val_accuracy'][-1]),
            'total_samples': community_model.metadata['total_samples']
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/contribute_sample', methods=['POST'])
def contribute_sample():
    if 'image' not in request.files:
        return jsonify({'error': 'No image uploaded'}), 400
    
    image = request.files['image']
    label = request.form.get('label')
    contributor_id = request.form.get('contributor_id', 'anonymous')
    
    if not label:
        return jsonify({'error': 'Label is required'}), 400
    
    try:
        filepath = community_model.add_training_sample(image, label, contributor_id)
        return jsonify({
            'message': 'Sample contributed successfully',
            'filepath': filepath,
            'total_contributions': len(community_model.metadata['contributions'])
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/train_community_model', methods=['POST'])
def train_community_model():
    epochs = int(request.form.get('epochs', 10))
    batch_size = int(request.form.get('batch_size', 32))
    
    if not os.path.exists(TRAINING_DATA_PATH) or not os.listdir(TRAINING_DATA_PATH):
        return jsonify({'error': 'No training data available'}), 400
    
    try:
        history = community_model.train_from_directory(
            TRAINING_DATA_PATH,
            batch_size=batch_size,
            epochs=epochs
        )
        
        return jsonify({
            'message': 'Community model trained successfully',
            'accuracy': float(history.history['accuracy'][-1]),
            'val_accuracy': float(history.history['val_accuracy'][-1]),
            'total_samples': community_model.metadata['total_samples']
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/predict', methods=['POST'])
def predict():
    if 'image' not in request.files:
        return jsonify({'error': 'No image uploaded'}), 400
    
    image = request.files['image']
    
    try:
        img = Image.open(image).convert('RGB')
        img = img.resize((community_model.img_width, community_model.img_height))
        img_array = np.array(img)
        img_array = np.expand_dims(img_array, 0)
        
        predictions = community_model.model.predict(img_array)
        predicted_class = int(np.argmax(predictions[0]))
        confidence = float(np.max(predictions[0]))
        
        return jsonify({
            'predicted_class': predicted_class,
            'confidence': confidence,
            'all_predictions': predictions[0].tolist()
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/model_stats', methods=['GET'])
def model_stats():
    return jsonify({
        'total_samples': community_model.metadata['total_samples'],
        'total_contributions': len(community_model.metadata['contributions']),
        'accuracy_history': community_model.metadata['accuracy_history'][-10:],
        'num_classes': community_model.num_classes
    }), 200

@app.route('/batch_upload', methods=['POST'])
def batch_upload():
    if 'images' not in request.files:
        return jsonify({'error': 'No images uploaded'}), 400
    
    images = request.files.getlist('images')
    labels = request.form.getlist('labels')
    contributor_id = request.form.get('contributor_id', 'anonymous')
    
    if len(images) != len(labels):
        return jsonify({'error': 'Number of images and labels must match'}), 400
    
    uploaded_files = []
    
    try:
        for image, label in zip(images, labels):
            filepath = community_model.add_training_sample(image, label, contributor_id)
            uploaded_files.append(filepath)
        
        return jsonify({
            'message': f'{len(uploaded_files)} samples contributed successfully',
            'uploaded_files': uploaded_files,
            'total_contributions': len(community_model.metadata['contributions'])
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)